using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests
{
    public static class TestHelpers
    {
        public static SchoolContext CreateInMemoryContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateSeededContext(string dbName = null)
        {
            var context = CreateInMemoryContext(dbName);
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var instructors = new[]
            {
                new Instructor { ID = 1, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11") },
                new Instructor { ID = 2, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06") },
                new Instructor { ID = 3, FirstMidName = "Roger", LastName = "Harui", HireDate = DateTime.Parse("1998-07-01") },
            };
            context.Instructors.AddRange(instructors);
            context.SaveChanges();

            var departments = new[]
            {
                new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 1 },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 2 },
                new Department { DepartmentID = 3, Name = "Engineering", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 3 },
            };
            context.Departments.AddRange(departments);
            context.SaveChanges();

            var courses = new[]
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 3 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 },
                new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = 2 },
            };
            context.Courses.AddRange(courses);
            context.SaveChanges();

            var students = new[]
            {
                new Student { ID = 10, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { ID = 11, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { ID = 12, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") },
            };
            context.Students.AddRange(students);
            context.SaveChanges();

            var enrollments = new[]
            {
                new Enrollment { EnrollmentID = 1, StudentID = 10, CourseID = 1050, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, StudentID = 10, CourseID = 4022, Grade = Grade.C },
                new Enrollment { EnrollmentID = 3, StudentID = 11, CourseID = 1045, Grade = Grade.B },
            };
            context.Enrollments.AddRange(enrollments);
            context.SaveChanges();

            var officeAssignments = new[]
            {
                new OfficeAssignment { InstructorID = 2, Location = "Smith 17" },
                new OfficeAssignment { InstructorID = 3, Location = "Gowan 27" },
            };
            context.OfficeAssignments.AddRange(officeAssignments);
            context.SaveChanges();

            var courseAssignments = new[]
            {
                new CourseAssignment { CourseID = 1050, InstructorID = 3 },
                new CourseAssignment { CourseID = 4022, InstructorID = 2 },
                new CourseAssignment { CourseID = 1045, InstructorID = 2 },
            };
            context.CourseAssignments.AddRange(courseAssignments);
            context.SaveChanges();
        }
    }
}

using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PersonTests
    {
        private class ConcretePerson : Person { }

        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var person = new ConcretePerson { LastName = "Smith", FirstMidName = "John" };
            Assert.Equal("Smith, John", person.FullName);
        }

        [Fact]
        public void FullName_HandlesEmptyFirstName()
        {
            var person = new ConcretePerson { LastName = "Smith", FirstMidName = "" };
            Assert.Equal("Smith, ", person.FullName);
        }

        [Fact]
        public void FullName_HandlesEmptyLastName()
        {
            var person = new ConcretePerson { LastName = "", FirstMidName = "John" };
            Assert.Equal(", John", person.FullName);
        }

        [Fact]
        public void Validation_RequiresLastName()
        {
            var person = new ConcretePerson { FirstMidName = "John" };
            var results = ValidateModel(person);
            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Validation_RequiresFirstMidName()
        {
            var person = new ConcretePerson { LastName = "Smith" };
            var results = ValidateModel(person);
            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Validation_LastNameMaxLength50()
        {
            var person = new ConcretePerson
            {
                LastName = new string('A', 51),
                FirstMidName = "John"
            };
            var results = ValidateModel(person);
            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Validation_FirstMidNameMaxLength50()
        {
            var person = new ConcretePerson
            {
                LastName = "Smith",
                FirstMidName = new string('A', 51)
            };
            var results = ValidateModel(person);
            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Validation_ValidPerson_NoErrors()
        {
            var person = new ConcretePerson
            {
                LastName = "Smith",
                FirstMidName = "John"
            };
            var results = ValidateModel(person);
            Assert.Empty(results);
        }

        [Fact]
        public void ID_GetSet()
        {
            var person = new ConcretePerson { ID = 42 };
            Assert.Equal(42, person.ID);
        }

        private static List<ValidationResult> ValidateModel(object model)
        {
            var context = new ValidationContext(model);
            var results = new List<ValidationResult>();
            Validator.TryValidateObject(model, context, results, true);
            return results;
        }
    }
}

