            Assert.Equal(42, dept.InstructorID);
        }

        [Fact]
        public void RowVersion_GetSet()
        {
            var version = new byte[] { 0x01, 0x02 };
            var dept = new Department { RowVersion = version };
            Assert.Equal(version, dept.RowVersion);
        }

        [Fact]
        public void Administrator_NavigationProperty()
        {
            var instructor = new Instructor { LastName = "Smith", FirstMidName = "John" };
            var dept = new Department { Administrator = instructor };
            Assert.Equal("Smith", dept.Administrator.LastName);
        }

        [Fact]
        public void Courses_NavigationProperty()
        {
            var dept = new Department
            {
                Courses = new List<Course> { new Course { Title = "Calculus" } }
            };
            Assert.Single(dept.Courses);
        }

        [Fact]
        public void Validation_NameTooShort()
        {
            var dept = new Department { Name = "AB", Budget = 100, StartDate = DateTime.Now };
            var results = ValidateModel(dept);
            Assert.Contains(results, r => r.MemberNames.Contains("Name"));
        }

        [Fact]
        public void Validation_NameTooLong()
        {
            var dept = new Department { Name = new string('A', 51), Budget = 100, StartDate = DateTime.Now };
            var results = ValidateModel(dept);
            Assert.Contains(results, r => r.MemberNames.Contains("Name"));
        }

        [Fact]
        public void Validation_ValidDepartment_NoErrors()
        {
            var dept = new Department { Name = "English", Budget = 350000, StartDate = DateTime.Now };
            var results = ValidateModel(dept);
            Assert.Empty(results);
        }

        private static List<ValidationResult> ValidateModel(object model)
        {
            var context = new ValidationContext(model);
            var results = new List<ValidationResult>();
            Validator.TryValidateObject(model, context, results, true);
            return results;
        }
    }
}

