using System.ComponentModel.DataAnnotations;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class NotificationTests
    {
        [Fact]
        public void Id_GetSet()
        {
            var n = new Notification { Id = 42 };
            Assert.Equal(42, n.Id);
        }

        [Fact]
        public void EntityType_GetSet()
        {
            var n = new Notification { EntityType = "Student" };
            Assert.Equal("Student", n.EntityType);
        }

        [Fact]
        public void EntityId_GetSet()
        {
            var n = new Notification { EntityId = "123" };
            Assert.Equal("123", n.EntityId);
        }

        [Fact]
        public void Operation_GetSet()
        {
            var n = new Notification { Operation = "CREATE" };
            Assert.Equal("CREATE", n.Operation);
        }

        [Fact]
        public void Message_GetSet()
        {
            var n = new Notification { Message = "Test message" };
            Assert.Equal("Test message", n.Message);
        }

        [Fact]
        public void CreatedAt_GetSet()
        {
            var now = DateTime.Now;
            var n = new Notification { CreatedAt = now };
            Assert.Equal(now, n.CreatedAt);
        }

        [Fact]
        public void CreatedBy_GetSet()
        {
            var n = new Notification { CreatedBy = "admin" };
            Assert.Equal("admin", n.CreatedBy);
        }

        [Fact]
        public void IsRead_DefaultFalse()
        {
            var n = new Notification();
            Assert.False(n.IsRead);
        }

        [Fact]
        public void IsRead_GetSet()
        {
            var n = new Notification { IsRead = true };
            Assert.True(n.IsRead);
        }

        [Fact]
        public void ReadAt_Nullable_GetSet()
        {
            var n = new Notification { ReadAt = null };
            Assert.Null(n.ReadAt);

            var now = DateTime.Now;
            n.ReadAt = now;
            Assert.Equal(now, n.ReadAt);
        }

        [Fact]
        public void Validation_RequiredFields()
        {
            var n = new Notification();
            var results = ValidateModel(n);
            Assert.Contains(results, r => r.MemberNames.Contains("EntityType"));
            Assert.Contains(results, r => r.MemberNames.Contains("EntityId"));
            Assert.Contains(results, r => r.MemberNames.Contains("Operation"));
            Assert.Contains(results, r => r.MemberNames.Contains("Message"));
        }

        [Fact]
        public void Validation_ValidNotification_NoErrors()
        {
            var n = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = DateTime.Now
            };
            var results = ValidateModel(n);
            Assert.Empty(results);
        }

        [Fact]
        public void Validation_EntityTypeTooLong()
        {
            var n = CreateValidNotification();
            n.EntityType = new string('A', 101);
            var results = ValidateModel(n);
            Assert.Contains(results, r => r.MemberNames.Contains("EntityType"));
        }

        [Fact]
        public void Validation_EntityIdTooLong()
        {
            var n = CreateValidNotification();
            n.EntityId = new string('1', 51);
            var results = ValidateModel(n);
            Assert.Contains(results, r => r.MemberNames.Contains("EntityId"));
        }

        [Fact]
        public void Validation_OperationTooLong()
        {
            var n = CreateValidNotification();
            n.Operation = new string('A', 21);
            var results = ValidateModel(n);
            Assert.Contains(results, r => r.MemberNames.Contains("Operation"));
        }

        [Fact]
        public void Validation_MessageTooLong()
        {
            var n = CreateValidNotification();
            n.Message = new string('A', 257);
            var results = ValidateModel(n);
            Assert.Contains(results, r => r.MemberNames.Contains("Message"));
        }

        [Fact]
        public void EntityOperation_EnumValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        private static Notification CreateValidNotification() => new()
        {
            EntityType = "Student",
            EntityId = "1",
            Operation = "CREATE",
            Message = "Test",
            CreatedAt = DateTime.Now
        };

        private static List<ValidationResult> ValidateModel(object model)
        {
            var context = new ValidationContext(model);
            var results = new List<ValidationResult>();
            Validator.TryValidateObject(model, context, results, true);
            return results;
        }
    }
}

