using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from static queue
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain queue after each test
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "admin");
            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_IncludesInMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");
            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("John Doe", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("42", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_MessageContainsCreated()
        {
            _service.SendNotification("Student", "1", "John", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.Contains("created", notification.Message.ToLower());
        }

        [Fact]
        public void SendNotification_UpdateOperation_MessageContainsUpdated()
        {
            _service.SendNotification("Student", "1", "John", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();

            Assert.Contains("updated", notification.Message.ToLower());
        }

        [Fact]
        public void SendNotification_DeleteOperation_MessageContainsDeleted()
        {
            _service.SendNotification("Student", "1", "John", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            Assert.Contains("deleted", notification.Message.ToLower());
        }

        [Fact]
        public void SendNotification_DefaultUserIsSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueEmpty()
        {
            var result = _service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_FIFO_Order()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("Student", first.EntityType);
            Assert.Equal("Course", second.EntityType);
        }

        [Fact]
        public void ReceiveNotification_DequeuedOnceOnly()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void MarkAsRead_WithNonExistentId_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(999));
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_WithNullDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "5", null, EntityOperation.CREATE, "admin");
            var notification = _service.ReceiveNotification();

            Assert.Contains("ID: 5", notification.Message);
        }

        [Fact]
        public void SendNotification_WithEmptyDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "5", "", EntityOperation.CREATE, "admin");
            var notification = _service.ReceiveNotification();

            Assert.Contains("ID: 5", notification.Message);
        }

        [Fact]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "5", "   ", EntityOperation.CREATE, "admin");
            var notification = _service.ReceiveNotification();

            Assert.Contains("ID: 5", notification.Message);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_MultipleNotifications_AllRetrievable()
        {
            for (int i = 0; i < 5; i++)
            {
                _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            int count = 0;
            while (_service.ReceiveNotification() != null) count++;
            Assert.Equal(5, count);
        }

        [Fact]
        public void SendNotification_TwoArgOverload_SetsMessageCorrectly()
        {
            _service.SendNotification("Department", "10", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            Assert.Equal("Department", notification.EntityType);
            Assert.Equal("10", notification.EntityId);
            Assert.Equal("DELETE", notification.Operation);
        }
    }
}

