using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void SchoolContext_HasStudentsDbSet()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            Assert.NotNull(context.Students);
        }

        [Fact]
        public void SchoolContext_HasCoursesDbSet()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            Assert.NotNull(context.Courses);
        }

        [Fact]
        public void SchoolContext_HasEnrollmentsDbSet()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            Assert.NotNull(context.Enrollments);
        }

        [Fact]
        public void SchoolContext_HasDepartmentsDbSet()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            Assert.NotNull(context.Departments);
        }

        [Fact]
        public void SchoolContext_HasInstructorsDbSet()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            Assert.NotNull(context.Instructors);
        }

        [Fact]
        public void SchoolContext_HasOfficeAssignmentsDbSet()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            Assert.NotNull(context.OfficeAssignments);
        }

        [Fact]
        public void SchoolContext_HasCourseAssignmentsDbSet()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            Assert.NotNull(context.CourseAssignments);
        }

        [Fact]
        public void SchoolContext_HasNotificationsDbSet()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            Assert.NotNull(context.Notifications);
        }

        [Fact]
        public void SchoolContext_HasPeopleDbSet()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            Assert.NotNull(context.People);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveStudent()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var student = new Student
