using ContosoUniversity.Data;
using ContosoUniversity.Models;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsStudents()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            Assert.True(context.Students.Any());
            Assert.Equal(8, context.Students.Count());
        }

        [Fact]
        public void Initialize_SeedsInstructors()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            Assert.True(context.Instructors.Any());
            Assert.Equal(5, context.Instructors.Count());
        }

        [Fact]
        public void Initialize_SeedsDepartments()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            Assert.True(context.Departments.Any());
            Assert.Equal(4, context.Departments.Count());
        }

        [Fact]
        public void Initialize_SeedsCourses()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            Assert.True(context.Courses.Any());
            Assert.Equal(7, context.Courses.Count());
        }

        [Fact]
        public void Initialize_SeedsEnrollments()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            Assert.True(context.Enrollments.Any());
            Assert.Equal(11, context.Enrollments.Count());
        }

        [Fact]
        public void Initialize_SeedsOfficeAssignments()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            Assert.True(context.OfficeAssignments.Any());
            Assert.Equal(3, context.OfficeAssignments.Count());
        }

        [Fact]
        public void Initialize_SeedsCourseAssignments()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            Assert.True(context.CourseAssignments.Any());
            Assert.Equal(8, context.CourseAssignments.Count());
        }

        [Fact]
        public void Initialize_DoesNotReseedIfDataExists()
        {
            using var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);
            var initialCount = context.Students.Count();

            // Initialize again
            DbInitializer.Initialize(context);
            var secondCount = context.Students.Count();

            Assert.Equal(initialCount, secondCount);
        }

        [Fact]
        public void Initialize_StudentNames_AreCorrect()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            var names = context.Students.Select(s => s.LastName).OrderBy(n => n).ToList();
            Assert.Contains("Alexander", names);
            Assert.Contains("Alonso", names);
            Assert.Contains("Anand", names);
            Assert.Contains("Barzdukas", names);
            Assert.Contains("Li", names);
            Assert.Contains("Justice", names);
            Assert.Contains("Norman", names);
            Assert.Contains("Olivetto", names);
        }

        [Fact]
        public void Initialize_DepartmentNames_AreCorrect()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            var names = context.Departments.Select(d => d.Name).ToList();
            Assert.Contains("English", names);
            Assert.Contains("Mathematics", names);
            Assert.Contains("Engineering", names);
            Assert.Contains("Economics", names);
        }

        [Fact]
        public void Initialize_DepartmentsHaveAdministrators()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            Assert.All(context.Departments.ToList(), d => Assert.NotNull(d.InstructorID));
        }
    }
}

