            _controller.Create(course, mockFile.Object);

            var savedCourse = _context.Courses.Find(6666);
            Assert.NotNull(savedCourse);
            Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

