        [InlineData(".png")]
        [InlineData(".gif")]
        [InlineData(".bmp")]
        public void CreatePost_AllowedExtensions_Accepted(string ext)
        {
            var courseId = 3000 + Math.Abs(ext.GetHashCode() % 1000);
            var course = new Course { CourseID = courseId, Title = "Ext Test", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFormFile($"test{ext}", "image/jpeg", 1024);

            _controller.Create(course, mockFile.Object);

