using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();

            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as System.Collections.Generic.List<Course>;
            Assert.NotNull(model);
            Assert.Equal(3, model.Count);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1050) as ViewResult;
            Assert.NotNull(result);
            var course = result.Model as Course;
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Details_ValidId_IncludesDepartment()
        {
            var result = _controller.Details(1050) as ViewResult;
            var course = result.Model as Course;
            Assert.NotNull(course.Department);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_GET_ReturnsView()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_GET_ReturnsEmptyCourse()
        {
            var result = _controller.Create() as ViewResult;
            Assert.IsType<Course>(result.Model);
        }

        #endregion

        #region Create POST

        [Fact]
        public void CreatePost_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };
            var result = _controller.Create(course, null);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void CreatePost_ValidCourse_SavedToDb()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "Saved Course",
                Credits = 4,
                DepartmentID = 1
            };
            _controller.Create(course, null);
            Assert.NotNull(_context.Courses.Find(8888));
        }

        [Fact]
        public void CreatePost_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 7777, Credits = 3, DepartmentID = 1 };
            var result = _controller.Create(course, null) as ViewResult;
            Assert.NotNull(result);
        }

        [Fact]
        public void CreatePost_WithValidImage_SavesFile()
        {
            var course = new Course { CourseID = 6666, Title = "With Image", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFormFile("test.jpg", "image/jpeg", 1024);

            _controller.Create(course, mockFile.Object);

            var savedCourse = _context.Courses.Find(6666);
            Assert.NotNull(savedCourse);
            Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

        [Fact]
        public void CreatePost_WithInvalidExtension_ReturnsView()
        {
            var course = new Course { CourseID = 5555, Title = "Bad Ext", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFormFile("test.exe", "application/octet-stream", 1024);

            var result = _controller.Create(course, mockFile.Object) as ViewResult;
            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void CreatePost_WithOversizedFile_ReturnsView()
        {
            var course = new Course { CourseID = 4444, Title = "Big File", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFormFile("test.jpg", "image/jpeg", 6 * 1024 * 1024);

            var result = _controller.Create(course, mockFile.Object) as ViewResult;
            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Theory]
        [InlineData(".jpg")]
        [InlineData(".jpeg")]
        [InlineData(".png")]
        [InlineData(".gif")]
        [InlineData(".bmp")]
        public void CreatePost_AllowedExtensions_Accepted(string ext)
        {
            var courseId = 3000 + Math.Abs(ext.GetHashCode() % 1000);
            var course = new Course { CourseID = courseId, Title = "Ext Test", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFormFile($"test{ext}", "image/jpeg", 1024);

            _controller.Create(course, mockFile.Object);

            Assert.NotNull(_context.Courses.Find(courseId));
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit(1050) as ViewResult;
            Assert.NotNull(result);
            var course = result.Model as Course;
            Assert.Equal("Chemistry", course.Title);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999999);
            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void EditPost_ValidCourse_RedirectsToIndex()
        {
            var course = _context.Courses.Find(1050);
            _context.Entry(course).State = EntityState.Detached;

            var updatedCourse = new Course
            {
                CourseID = 1050,
                Title = "Updated Chemistry",
                Credits = 4,
                DepartmentID = 3
            };
            var result = _controller.Edit(updatedCourse, null);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void EditPost_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, DepartmentID = 3 };
            var result = _controller.Edit(course, null) as ViewResult;
            Assert.NotNull(result);
        }

        [Fact]
        public void EditPost_WithInvalidExtension_ReturnsView()
        {
            var course = _context.Courses.Find(1050);
            _context.Entry(course).State = EntityState.Detached;

            var updatedCourse = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 3 };
            var mockFile = CreateMockFormFile("test.exe", "application/octet-stream", 1024);

            var result = _controller.Edit(updatedCourse, mockFile.Object) as ViewResult;
            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void EditPost_WithOversizedFile_ReturnsView()
        {
            var course = _context.Courses.Find(1050);
            _context.Entry(course).State = EntityState.Detached;

            var updatedCourse = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 3 };
            var mockFile = CreateMockFormFile("test.jpg", "image/jpeg", 6 * 1024 * 1024);

            var result = _controller.Edit(updatedCourse, mockFile.Object) as ViewResult;
            Assert.NotNull(result);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050) as ViewResult;
            Assert.NotNull(result);
            var course = result.Model as Course;
            Assert.Equal("Chemistry", course.Title);
        }

        #endregion

        #region DeleteConfirmed

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(1050);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesCourse()
        {
            _controller.DeleteConfirmed(1050);
            Assert.Null(_context.Courses.Find(1050));
        }

        #endregion

        private Mock<IFormFile> CreateMockFormFile(string fileName, string contentType, long length)
        {
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.ContentType).Returns(contentType);
            mockFile.Setup(f => f.Length).Returns(length);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));
            return mockFile;
        }
    }
}

