using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as System.Collections.Generic.List<Department>;
            Assert.NotNull(model);
            Assert.Equal(3, model.Count);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Details(1) as ViewResult;
            Assert.NotNull(result);
            var dept = result.Model as Department;
            Assert.Equal("English", dept.Name);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);
            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_GET_ReturnsView()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Create POST

        [Fact]
        public void CreatePost_ValidDepartment_RedirectsToIndex()
        {
            var dept = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = new DateTime(2023, 9, 1),
                InstructorID = 1
            };
            var result = _controller.Create(dept);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void CreatePost_ValidDepartment_SavedToDb()
        {
            var dept = new Department
            {
                Name = "Biology",
                Budget = 150000,
                StartDate = new DateTime(2023, 9, 1)
            };
            _controller.Create(dept);
            Assert.Contains(_context.Departments, d => d.Name == "Biology");
        }

        [Fact]
        public void CreatePost_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department { Budget = 100000, StartDate = DateTime.Now };
            var result = _controller.Create(dept) as ViewResult;
            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Edit(1) as ViewResult;
            Assert.NotNull(result);
            var dept = result.Model as Department;
            Assert.Equal("English", dept.Name);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);
            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void EditPost_ValidDepartment_RedirectsToIndex()
        {
            var dept = _context.Departments.Find(1);
            _context.Entry(dept).State = EntityState.Detached;

            var updated = new Department
            {
                DepartmentID = 1,
                Name = "Updated English",
                Budget = 400000,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 1
            };
            var result = _controller.Edit(updated);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void EditPost_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department { DepartmentID = 1, Budget = 100000, StartDate = DateTime.Now };
            var result = _controller.Edit(dept) as ViewResult;
            Assert.NotNull(result);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Delete(1) as ViewResult;
            Assert.NotNull(result);
            var dept = result.Model as Department;
            Assert.Equal("English", dept.Name);
        }

        [Fact]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);
            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region DeleteConfirmed

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(1);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesDepartment()
        {
            _controller.DeleteConfirmed(1);
            Assert.Null(_context.Departments.Find(1));
        }

        #endregion
    }
}

