using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithInstructorIndexData()
        {
            var result = _controller.Index(null, null) as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model);
            Assert.NotNull(model.Instructors);
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            var result = _controller.Index(null, null) as ViewResult;
            var model = result.Model as InstructorIndexData;
            var names = model.Instructors.Select(i => i.LastName).ToList();
            Assert.Equal(names.OrderBy(n => n), names);
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            // Instructor ID 2 (Fakhouri) has course assignments
            var result = _controller.Index(2, null) as ViewResult;
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model.Courses);
            Assert.True(model.Courses.Any());
        }

        [Fact]
        public void Index_WithInstructorId_SetsViewBag()
        {
            _controller.Index(2, null);
            Assert.Equal(2, _controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Index_WithCourseId_PopulatesEnrollments()
        {
            // Instructor 2 teaches course 4022; course 4022 has enrollments
            var result = _controller.Index(2, 4022) as ViewResult;
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Index_WithCourseId_SetsViewBag()
        {
            _controller.Index(2, 4022);
            Assert.Equal(4022, _controller.ViewBag.CourseID);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Details(1) as ViewResult;
            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);
            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_GET_ReturnsView()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
            Assert.NotNull(instructor.CourseAssignments);
        }

        [Fact]
        public void Create_GET_PopulatesAssignedCourseData()
        {
            _controller.Create();
            var courses = _controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
            Assert.Equal(3, courses.Count);
        }

        #endregion

        #region Create POST

        [Fact]
        public void CreatePost_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1)
            };
            var result = _controller.Create(instructor, null);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void CreatePost_ValidInstructor_SavedToDb()
        {
            var instructor = new Instructor
            {
                LastName = "Saved",
                FirstMidName = "Instructor",
                HireDate = new DateTime(2023, 1, 1)
            };
            _controller.Create(instructor, null);
            Assert.Contains(_context.Instructors, i => i.LastName == "Saved");
        }

        [Fact]
        public void CreatePost_WithSelectedCourses_CreatesCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "WithCourses",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1)
            };
            var result = _controller.Create(instructor, new[] { "1050", "4022" });
            Assert.IsType<RedirectToActionResult>(result);
            var saved = _context.Instructors.First(i => i.LastName == "WithCourses");
            // The instructor should be created (course assignments added in memory)
            Assert.NotNull(saved);
        }

        [Fact]
        public void CreatePost_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            var result = _controller.Create(instructor, null) as ViewResult;
            Assert.NotNull(result);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsView()
        {
            var result = _controller.Edit(1) as ViewResult;
            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Delete(1) as ViewResult;
            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        [Fact]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);
            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region DeleteConfirmed

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(1);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesInstructor()
        {
            _controller.DeleteConfirmed(1);
            Assert.Null(_context.Instructors.Find(1));
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            // Instructor 1 is the administrator of Department 1
            _controller.DeleteConfirmed(1);
            var dept = _context.Departments.Find(1);
            Assert.Null(dept.InstructorID);
        }

        #endregion
    }
}

