using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;
        private readonly NotificationService _notificationService;

        public NotificationsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            _notificationService = new NotificationService();
            // Drain the shared queue
            while (_notificationService.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain the queue after each test
            while (_notificationService.ReceiveNotification() != null) { }
            _notificationService.Dispose();
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void GetNotifications_ReturnsJson()
        {
            var result = _controller.GetNotifications();
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithZeroCount()
        {
            var result = _controller.GetNotifications();
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Enqueue some notifications via the shared static queue
            _notificationService.SendNotification("Student", "1", EntityOperation.CREATE);
            _notificationService.SendNotification("Course", "2", EntityOperation.UPDATE);

            var result = _controller.GetNotifications();
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void MarkAsRead_ReturnsJson()
        {
            var result = _controller.MarkAsRead(1);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void MarkAsRead_NonExistentId_ReturnsJson()
        {
            var result = _controller.MarkAsRead(999);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            // Enqueue more than 10 notifications
            for (int i = 0; i < 15; i++)
            {
                _notificationService.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();
            Assert.IsType<JsonResult>(result);
            // The controller limits to 10 max per call
        }
    }
}

